css.web:
.obs-story-title {
  text-align: center;
}

.article img {
  display: block;
  margin: 0 auto;
  width: 100%;
  max-width: 640px;
}

a.header-link {
  font-weight: inherit !important;
  font-size: inherit !important;
  color: #000000;
  text-decoration: none;
}

a.header-link:hover::after {
  content: '#';
  padding-left: 5px;
  color: blue;
  display: inline-block;
}

.cover-page {
  text-align: center;
  padding-top: 2rem;
}

.cover-page .header-title {
  display: none;
}

.cover-page .title-logo {
  display: block;
  margin: 0 auto 1rem auto;
  width: 180px;
  max-width: 60%;
  height: auto;
}

.cover-page .cover-header,
.cover-page .cover-version,
.cover-page .cover-book-title,
.cover-page .cover-resource-title {
  text-align: center;
  margin-left: auto;
  margin-right: auto;
}

.cover-page .cover-version {
  color: #666;
  font-weight: normal;
}

css.print:
.obs-story-title {
  text-align: center;
}

#pagedjs-print .obs-story-title {
  break-after: page !important;
  padding-top: 300px;
}

.article {
  break-before: auto !important;
  break-after: auto !important;
}
